/** Synced from [A Design Line Carhartt catalog](https://www.adesignline.com/p/catalog/39049732-7d64-47e0-93e0-7a77d01f8b50/carhartt) — 135 SKUs */

function money(amount: number) {
  return { amount: amount.toFixed(2), currencyCode: 'USD' as const };
}

function img(url: string, altText: string) {
  return { url, altText, width: 2400, height: 2400 };
}

function variant(
  id: string,
  title: string,
  amount: number,
  selectedOptions: { name: string; value: string }[] = []
) {
  return {
    id,
    title,
    availableForSale: true,
    selectedOptions,
    price: money(amount)
  };
}

function carharttProduct(spec: {
  id: string;
  handle: string;
  title: string;
  description: string;
  descriptionHtml: string;
  price: number;
  imageUrl: string;
  supplierSku: string;
  productionDays: number;
  minQuantity: number;
}): VercelProduct {
  const {
    id,
    handle,
    title,
    description,
    descriptionHtml,
    price,
    imageUrl,
    supplierSku,
    productionDays,
    minQuantity
  } = spec;
  const image = img(imageUrl, title);
  const options = [{ id: 'title', name: 'Title', values: ['Default'] }];
  const variants = [variant(`${id}-default`, title, price)];
  return {
    id,
    handle: `/product/${handle}`,
    availableForSale: true,
    title,
    description,
    descriptionHtml,
    options,
    priceRange: { minVariantPrice: money(price), maxVariantPrice: money(price) },
    variants,
    featuredImage: image,
    images: [image],
    seo: { title: title.slice(0, 70), description: description.slice(0, 160) },
    catalog: {
      supplierSku,
      productionDays,
      minQuantity
    },
    tags: ['carhartt', 'brands', 'categories', 'men', 'women'],
    updatedAt: new Date().toISOString()
  };
}

